import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionSecure {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a file name to display its content: ");
            String fileName = reader.readLine();

            // Validate the input to ensure it contains only allowed characters (e.g., alphanumeric, dot, underscore)
            if (!fileName.matches("[a-zA-Z0-9_.]+")) {
                System.out.println("Invalid file name");
                return;
            }

            // Use ProcessBuilder to construct and execute the command safely
            Process process = new ProcessBuilder("cat", fileName).start();
            BufferedReader inputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));

            String line;
            while ((line = inputReader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

